    font-size: 40px;
  }

  h1 span {
    font-size: 40px;
  }

  .footer-row:nth-child(1) {
    display: flex;
    flex-direction: column;
    gap: 4em;
  }

  .card {
    width: 200px;
  }

  .card-3 {
