  justify-content: space-between;
}

.hero-row:nth-child(2) .header h1 {
  text-align: right;
}

.hero-row p {
  width: 240px;
  margin-left: 8em;
}

/* works-header */
.works-header {
  margin-top: 8em;
}

.works-header .container {
  display: flex;
  flex-direction: column;
}

.works-header-row {
  display: flex;
  justify-content: space-between;
}

.works-header-row:nth-child(2) {
  padding-left: 20%;
}

.works-header-copy {
  width: 100%;
  display: flex;
  justify-content: center;
  margin: 4em 0;
}

.works-header-copy p {
  width: 240px;
}

/* works */
.works .container {
  display: flex;
  flex-direction: column;
  gap: 4em;
  padding-bottom: 8em;
}

.work-item {
  width: 100%;
}

.work-item-index p {
  font-size: var(--font-tiny);
}

.work-item-name {
  width: 100%;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.5em 0;
  gap: 2em;
}

.work-item-name p:nth-child(1) {
