}

.awards-header-row {
  display: flex;
  justify-content: space-between;
}

.awards-header-row:nth-child(2) {
  padding-left: 8em;
}

.awards-header-row:nth-child(3) {
  padding-left: 24em;
}

.awards .container {
  display: flex;
  flex-direction: column;
}

.award {
  width: 100%;
  display: flex;
  padding: 1.5em 0;
  border-bottom: 2px dashed var(--color-accent);
}

.award:nth-child(1) p {
  font-size: var(--font-tiny);
}

.award p:nth-child(1) {
  flex: 3;
}

.award p:nth-child(2) {
  flex: 2;
}

.award p:nth-child(3) {
  flex: 2;
}

.award p:nth-child(4) {
  flex: 1;
  display: flex;
  justify-content: flex-end;
}

.contact {
  position: relative;
  text-align: center;
  padding: 24em 0 8em 0;
}

@media (max-width: 900px) {
  .hero-row p {
    margin-left: 0;
  }

  .works .container {
    gap: 2em;
  }

  .hero-row:nth-child(2) {
    flex-direction: column;
    gap: 4em;
  }

  .skills-row {
    flex-direction: column;
  }

  .skill {
    aspect-ratio: 15 / 5;
  }

